def main():
    data = json.loads(FILE.read_text(encoding="utf-8-sig"))
    enriched = 0

    # Add fully specified entries
    for slug, fields in {**NEW_DATA, **SHARED}.items():
        if slug not in data:
            continue
        if "website" in data[slug]:
            print(f"[SKIP] {slug}")
            continue
        data[slug].update(fields)
        print(f"[OK]   {slug}")
        enriched += 1

    # Add physics-specific entries with template
    for slug, (website, ref, strengths, employers, emp_rate, salary) in PHYSICS_SPECIFIC.items():
        if slug not in data:
            continue
        if "website" in data[slug]:
            print(f"[SKIP] {slug}")
            continue
        entry = make_entry(slug, website, ref, strengths, employers, emp_rate, salary)
        data[slug].update(entry)
        print(f"[OK]   {slug} (template)")
        enriched += 1

    FILE.write_text(json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")
    print(f"\nDone — {enriched} universities enriched.")
    remaining = [s for s, v in data.items() if "website" not in v]
    if remaining:
        print(f"Still missing: {remaining}")


if __name__ == "__main__":
    main()
